'use client';

import React, { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Star, Send } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useToast } from '@/hooks/use-toast';

export function FeedbackCard() {
  const [rating, setRating] = useState(0);
  const [feedback, setFeedback] = useState('');
  const { toast } = useToast();

  const handleSubmit = () => {
    toast({
      title: "Feedback Submitted",
      description: "Thank you for your response!",
    });
    setRating(0);
    setFeedback('');
  };

  return (
    <Card className="shadow-md h-full flex flex-col">
      <CardHeader className="py-4">
        <CardTitle className="text-lg font-bold text-[#1e293b]">Rate Your Experience</CardTitle>
      </CardHeader>
      <CardContent className="flex-1 flex flex-col gap-6">
        <div className="flex flex-col items-center justify-center p-4 bg-[#f8fafc] rounded-xl border border-dashed border-[#cbd5e1]">
          <div className="flex gap-2">
            {[1, 2, 3, 4, 5].map((star) => (
              <button
                key={star}
                type="button"
                onClick={() => setRating(star)}
                className="focus:outline-none transition-transform hover:scale-110"
              >
                <Star
                  className={cn(
                    "w-8 h-8",
                    star <= rating ? "fill-yellow-400 text-yellow-400" : "text-[#cbd5e1]"
                  )}
                />
              </button>
            ))}
          </div>
          <span className="text-xs font-semibold text-muted-foreground mt-2">Click to rate</span>
        </div>

        <Textarea
          placeholder="Share your feedback with us..."
          className="resize-none h-32 border-[#cbd5e1] focus:ring-primary rounded-xl"
          value={feedback}
          onChange={(e) => setFeedback(e.target.value)}
        />

        <Button
          className="w-full mt-auto bg-gradient-to-r from-primary to-accent hover:opacity-95 text-white font-bold h-12 rounded-xl gap-2 shadow-lg border-0"
          onClick={handleSubmit}
        >
          <Send className="h-5 w-5" />
          Submit Feedback
        </Button>
      </CardContent>
    </Card>
  );
}
